  html {
    font-size: 16px;
  }
}

body {
  margin: 0;
  min-height: 100vh;
  color: #e7eefc;
  background: radial-gradient(circle at top center, #17203a 0%, #090b14 38%, #020309 100%);
  font-family: "Segoe UI", system-ui, -apple-system, BlinkMacSystemFont, "Helvetica Neue", Arial, sans-serif;
}

header {
  position: sticky;
  top: 0;
  z-index: 1030;
}

.app-navbar {
  background: rgba(11, 14, 25, 0.92);
  border-bottom: 1px solid rgba(255, 255, 255, 0.06);
  box-shadow: 0 18px 45px rgba(0, 0, 0, 0.28);
  padding: 0.85rem 0;
}

.app-brand {
  color: #f7fbff;
  font-size: 1.05rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.brand-mark {
  display: inline-block;
  margin-right: 0.6rem;
  color: #7bffea;
  font-size: 1.35rem;
  vertical-align: middle;
}

.navbar-nav {
  gap: 0.6rem;
}

.navbar-nav .nav-link {
  color: rgba(231, 238, 252, 0.78);
  padding: 0.6rem 0.8rem;
  font-size: 0.95rem;
  transition: color 0.2s ease, transform 0.2s ease, background-color 0.2s ease;
}

.navbar-nav .nav-link:hover,
.navbar-nav .nav-link:focus,
.navbar-nav .nav-link.active {
  color: #ffffff;
  transform: translateY(-1px);
}

.navbar-nav .nav-link.active {
  background: rgba(123, 255, 234, 0.13);
  border-radius: 999px;
}

.navbar-toggler {
  border: 1px solid rgba(255, 255, 255, 0.18);
  border-radius: 999px;
  width: 48px;
  height: 48px;
  padding: 0.6rem;
  background: rgba(255, 255, 255, 0.06);
}

.navbar-toggler-icon {
  position: relative;
  display: block;
  width: 22px;
  height: 2px;
  background-color: #f3f7ff;
}

.navbar-toggler-icon::before,
.navbar-toggler-icon::after {
  content: "";
  position: absolute;
  width: 22px;
  height: 2px;
  background-color: #f3f7ff;
  left: 0;
}

.navbar-toggler-icon::before {
  top: -7px;
}

.navbar-toggler-icon::after {
  top: 7px;
}

.container {
  max-width: 1140px;
}

main.pb-3 {
  padding-top: 2rem;
  padding-bottom: 2.5rem;
}

.page-content {
  background: rgba(9, 13, 25, 0.92);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 1.75rem;
  box-shadow: 0 32px 90px rgba(0, 0, 0, 0.32);
  padding: 2rem;
  margin-top: 1rem;
}

.footer {
  color: rgba(190, 209, 245, 0.72);
  background: transparent;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  padding: 1.4rem 0;
}

.footer a {
  color: #7ee2ff;
  text-decoration: none;
}

.footer a:hover {
  color: #a3f2ff;
}

@media (max-width: 991px) {
  .navbar-nav {
    gap: 0.4rem;
  }

  .page-content {
    padding: 1.4rem;
  }
}

