{"filePath":"c:\Users\drvoj\Documents\GitHub\aspnet-tvz\src\Playlist\Playlist\wwwroot\css\site.css","newString":".footer a:hover {
  color: #a3f2ff;
}

.hero-section {
  text-align: center;
  padding: 4rem 2rem;
  background: linear-gradient(135deg, rgba(123, 255, 234, 0.1) 0%, rgba(11, 14, 25, 0.8) 100%);
  border-radius: 1.75rem;
  margin-bottom: 3rem;
}

.hero-title {
  font-size: clamp(3rem, 5vw, 5rem);
  font-weight: 900;
  color: #f2f8ff;
  margin-bottom: 0.5rem;
  letter-spacing: 0.1em;
  text-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
}

.hero-subtitle {
  font-size: 1.25rem;
  color: rgba(231, 238, 252, 0.8);
  margin-bottom: 2rem;
}

.hero-actions {
  display: flex;
  gap: 1rem;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  display: inline-flex;
  align-items: center;
  padding: 0.75rem 1.5rem;
  border-radius: 999px;
  font-weight: 600;
  text-decoration: none;
  transition: all 0.2s ease;
  border: none;
  cursor: pointer;
}

.btn-primary {
  background: #7bffea;
  color: #020309;
}

.btn-primary:hover {
  background: #a3f2ff;
  transform: translateY(-2px);
  box-shadow: 0 8px 25px rgba(123, 255, 234, 0.3);
}

.btn-secondary {
  background: rgba(255, 255, 255, 0.1);
  color: #f2f8ff;
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.btn-secondary:hover {
  background: rgba(255, 255, 255, 0.2);
  transform: translateY(-2px);
}

.btn-outline {
  background: transparent;
  color: #7ee2ff;
  border: 1px solid #7ee2ff;
}

.btn-outline:hover {
  background: rgba(126, 226, 255, 0.1);
  color: #a3f2ff;
}

.top-songs-section,
.featured-artists-section {
  margin-bottom: 3rem;
}

.top-songs-section h2,
.featured-artists-section h2 {
  text-align: center;
  margin-bottom: 2rem;
  color: #a3d8ff;
}

.songs-grid,
.artists-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 1.5rem;
}

.song-card,
.artist-card {
  background: rgba(9, 13, 25, 0.8);
  border: 1px solid rgba(255, 255, 255, 0.05);
  border-radius: 1rem;
  padding: 1.5rem;
  text-align: center;
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.song-card:hover,
.artist-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 30px rgba(0, 0, 0, 0.4);
}

.song-card h3,
.artist-card h3 {
  color: #f2f8ff;
  margin-bottom: 0.5rem;
  font-size: 1.25rem;
}

.song-card p,
.artist-card p {
  color: rgba(231, 238, 252, 0.8);
  margin-bottom: 0.5rem;
}

.song-card span {
  color: #7bffea;
  font-size: 0.9rem;
}

